settings.json <pre><code>// vim settings
"vim.leader": "&lt;Space&gt;",
"vim.useSystemClipboard": true,
"vim.foldfix": true,
"vim.hlsearch": true,
"vim.shell": "C:\\Users\\kilos\\scoop\\apps\\git\\current\\git-bash.exe",
"vim.autoSwitchInputMethod.enable": true,
"vim.autoSwitchInputMethod.defaultIM": "1033",
"vim.autoSwitchInputMethod.obtainIMCmd": "C:\\Users\\kilos\\app\\im-select.exe",
"vim.autoSwitchInputMethod.switchIMCmd": "C:\\Users\\kilos\\app\\im-select.exe {im}",
"vim.handleKeys": {
  "&lt;C-k&gt;": false,
  "&lt;C-b&gt;": false,
  "&lt;C-j&gt;": false,
  "&lt;C-s&gt;": false
},
"vim.insertModeKeyBindingsNonRecursive": [
  {
    "before": ["j", "k"],
    "after": ["&lt;Esc&gt;"]
  }
],
"vim.normalModeKeyBindingsNonRecursive": [
  // functional
  {
    // execute python file
    "before": ["&lt;leader&gt;", "c", "e"],
    "commands": ["python.execInDedicatedTerminal"]
  },
  // personal habit
  {
    // reundo
    "before": ["U"],
    "commands": ["&lt;C-r&gt;"],
  },
  {
    // split line, correspond to J for join line
    "before": ["K"],
    "commands": ["lineBreakInsert"],
    "silent": true
  },
  {
    // save file
    "before": ["&lt;leader&gt;", "w"],
    "commands": ["workbench.action.files.save"]
  },
  {
    // close file
    "before": ["&lt;leader&gt;", "q"],
    "commands": ["workbench.action.closeActiveEditor"]
  },
  {
    // no highlight
    "before": ["&lt;leader&gt;", "/"],
    "commands": [":noh"]
  },
  // group control
  {
    // move to left group
    "before": ["&lt;C-h&gt;"],
    "after": ["&lt;C-w&gt;", "h"]
  },
  {
    // move to right group
    "before": ["&lt;C-l&gt;"],
    "after": ["&lt;C-w&gt;", "l"]
  },
  // useful setting
  {
    // show command line
    "before": ["&lt;leader&gt;", "p"],
    "commands": ["workbench.action.showCommands"]
  },
  {
    // go to file
    "before": ["&lt;leader&gt;", "f"],
    "commands": ["workbench.action.quickOpen"]
  },
  {
    // go to buffer
    "before": ["&lt;leader&gt;", "b"],
    "commands": ["workbench.action.showAllEditors"]
  },
  {
    // go to symbol
    "before": ["&lt;leader&gt;", "o"],
    "commands": ["workbench.action.gotoSymbol"]
  }
],
</code></pre>
